begin;
create extension if not exists pgcrypto;
create table if not exists public.langar_settings(key text primary key,value jsonb not null default 'null'::jsonb,updated_at timestamptz not null default now(),updated_by uuid);
create table if not exists public.reservations(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,customer_name text not null,phone text not null,reservation_date date not null,reservation_time time not null,guests int not null check(guests between 1 and 30),area text default 'inside',occasion text,high_chair boolean default false,note text,status text not null default 'pending' check(status in('pending','confirmed','rejected','cancelled','completed','no_show')),admin_note text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create unique index if not exists reservations_active_slot_uq on public.reservations(reservation_date,reservation_time) where status in('pending','confirmed');
create table if not exists public.gallery_items(id uuid primary key default gen_random_uuid(),image_url text not null,storage_path text,title_en text,title_hr text,category text,sort_order int default 0,active boolean default true,created_at timestamptz default now());
insert into storage.buckets(id,name,public) values('langar-gallery','langar-gallery',true) on conflict(id) do update set public=true;
alter table public.reservations enable row level security;alter table public.gallery_items enable row level security;alter table public.langar_settings enable row level security;
drop policy if exists "reservation own read" on public.reservations;create policy "reservation own read" on public.reservations for select to authenticated using(user_id=auth.uid() or exists(select 1 from public.admin_members a where a.user_id=auth.uid() and a.active));
drop policy if exists "gallery public read" on public.gallery_items;create policy "gallery public read" on public.gallery_items for select using(active or exists(select 1 from public.admin_members a where a.user_id=auth.uid() and a.active));
drop policy if exists "gallery admin write" on public.gallery_items;create policy "gallery admin write" on public.gallery_items for all to authenticated using(exists(select 1 from public.admin_members a where a.user_id=auth.uid() and a.active)) with check(exists(select 1 from public.admin_members a where a.user_id=auth.uid() and a.active));
drop policy if exists "settings public read" on public.langar_settings;create policy "settings public read" on public.langar_settings for select using(true);
drop policy if exists "settings admin write" on public.langar_settings;create policy "settings admin write" on public.langar_settings for all to authenticated using(exists(select 1 from public.admin_members a where a.user_id=auth.uid() and a.active)) with check(exists(select 1 from public.admin_members a where a.user_id=auth.uid() and a.active));
drop policy if exists "gallery storage public" on storage.objects;create policy "gallery storage public" on storage.objects for select using(bucket_id='langar-gallery');
drop policy if exists "gallery storage admin" on storage.objects;create policy "gallery storage admin" on storage.objects for all to authenticated using(bucket_id='langar-gallery' and exists(select 1 from public.admin_members a where a.user_id=auth.uid() and a.active)) with check(bucket_id='langar-gallery' and exists(select 1 from public.admin_members a where a.user_id=auth.uid() and a.active));
create or replace function public.customer_create_reservation_v520(p_date date,p_time time,p_name text,p_phone text,p_guests int,p_note text default '') returns uuid language plpgsql security definer set search_path=public as $$declare rid uuid;begin if auth.uid() is null then raise exception 'Login required';end if;insert into reservations(user_id,customer_name,phone,reservation_date,reservation_time,guests,note) values(auth.uid(),trim(p_name),trim(p_phone),p_date,p_time,p_guests,p_note) returning id into rid;return rid;exception when unique_violation then raise exception 'This time is already reserved';end$$;
grant execute on function public.customer_create_reservation_v520(date,time,text,text,int,text) to authenticated;
create or replace function public.admin_update_reservation_v520(p_id uuid,p_status text,p_note text default '') returns void language plpgsql security definer set search_path=public as $$declare r reservations;begin if not exists(select 1 from admin_members a where a.user_id=auth.uid() and a.active) then raise exception 'Admin required';end if;update reservations set status=p_status,admin_note=p_note,updated_at=now() where id=p_id returning * into r;if r.id is null then raise exception 'Reservation not found';end if;if to_regclass('public.inbox_messages') is not null then insert into inbox_messages(user_id,title,body,priority,created_at,is_deleted) values(r.user_id,'Reservation update',format('Your reservation for %s at %s is now %s. %s',r.reservation_date,to_char(r.reservation_time,'HH24:MI'),p_status,coalesce(p_note,'')),'important',now(),false);end if;end$$;
grant execute on function public.admin_update_reservation_v520(uuid,text,text) to authenticated;
do $$begin if to_regclass('public.inbox_messages') is not null then alter table public.inbox_messages add column if not exists priority text default 'normal';alter table public.inbox_messages add column if not exists shown_at timestamptz;end if;end$$;
create or replace function public.customer_delete_inbox_v520(p_message_id uuid) returns void language plpgsql security definer set search_path=public as $$begin update inbox_messages set is_deleted=true,deleted_at=now() where id=p_message_id and user_id=auth.uid();end$$;
grant execute on function public.customer_delete_inbox_v520(uuid) to authenticated;
create or replace view public.public_reviews_v520 as select r.id,coalesce((r.item_reviews->0->>'rating')::int,r.overall_rating,5) rating,coalesce(r.item_reviews->0->>'comment',r.public_comment,r.comment,'') comment,coalesce(r.item_reviews->0->>'item_name_en',r.item_reviews->0->>'item_name_hr','') item_name,coalesce(r.customer_name,'Langar guest') customer_name,coalesce(r.published_at,r.created_at) published_at from public.order_reviews r where coalesce(r.is_public,false)=true;
grant select on public.public_reviews_v520 to anon,authenticated;
alter publication supabase_realtime add table public.reservations;
insert into public.langar_settings(key,value) values('receipt_footer','"Thank you for choosing Langar Bar!"'::jsonb),('receipt_align','"center"'::jsonb),('receipt_size','"13"'::jsonb),('admin_sound','true'::jsonb),('cancel_window_minutes','"2"'::jsonb),('support_phone','"+385916062535"'::jsonb) on conflict(key) do nothing;
commit;
